var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"후훗, 준에게 들었어.","JPN":"ふふ、ジュンから聞いたよ。","ENG":"Hah hah, I heard from Jun.","TWN":"呵呵～朱恩有跟我提過，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"이게…… <color=#ffd34c>종신 계약</color>이라는 거지? 나도 다 알고 있다구!","JPN":"これが……<color=#ffd34c>終身契約</color>ってことだよね？　私も全部知っているよ！","ENG":"So this is... the <color=#ffd34c>Lifetime Contract</color>, right? I knew that!","TWN":"這個……叫<color=#ffd34c>終身契約</color>對吧？我知道喔！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"하지만 전에 있던 회사 선배들이 말하길, 계약이라는 건 항상 신중해야 한다더라?","JPN":"しかし、前にいた会社の先輩たちが言うには、契約というのは常に慎重になるべきらしい。","ENG":"But I heard from a former colleague that I have to be careful when signing contracts...","TWN":"可是前公司的同事跟我說，合約這種東西一定要很謹慎，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"나중에 어떻게 꼬투리가 잡힐 지 모르니까!","JPN":"あとから揚げ足を取られるかもしれないからね！","ENG":"Because you never know how they’re going to twist their words around later!","TWN":"誰知道之後會不會被抓到小辮子！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"……엣헴!! 한 마디로 파사의 추적자인 나와 계약하려면 평범한 조건으로는 어림도 없다, 이 말씀!","JPN":"……えっへん！！　つまり、破邪の追跡者の私と契約するには、普通の条件ではできないってことだ！","ENG":"...Ahem!! In other words, I, the Chaser of Evil, am not signing anything under normal conditions!","TWN":"……嘿嘿！！總之意思就是，合約條件太普通的話，你就別想和我這個破邪追擊者簽約！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"자, 그럼 하나하나 따져볼까?","JPN":"さて、ひとつずつ確かめていこう。","ENG":"Alright then! Shall we go over it line by line?","TWN":"我們來一條一條看看吧～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"우선, 카운터 4대 보험을 들어줘. 싸우다가 다치면 아프니까. 그 정도는 해줄 수 있지?","JPN":"まずは、カウンターの四大保険を掛けてくれ。戦闘中に怪我したら痛いからね。それくらいはしてくれるよね？","ENG":"First, I want the Counter Health Insurance plan because of the nature of my job. You can do that for me, right?","TWN":"首先，我要求要制裁者4大保險，萬一出勤時受傷的話，我會很痛欸！這個要求應該不過分吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"그리고 시급은 당연히 현행 기본 시급을 맞춰 줘! 꼭이야, 꼭!!","JPN":"そして時給は当然、現行の基本時給に合わせてほしい。\\nこれは絶対だよ、絶対！！","ENG":"Also, wages have to be equal to the current minimum wage! Don’t try to weasel your way out of that one!","TWN":"時薪的話，當然要比照現在的時薪囉！一個子兒都不能少！知道嗎！！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"음…… 아! 그리고 탕비실에 있는 간식은 마음대로 먹을 수 있게 해줘!","JPN":"えっと……あ！　それから休憩室にあるおやつは好きなように食べさせて！","ENG":"And... Ooh! I want to be able to eat all the snacks available at the pantry!","TWN":"嗯……還有！茶水間的零食要無限量供應！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"특히, 순한 맛 컵라면은 항상 가득 채워줘! 매운 건 못 먹는 단 말이야!","JPN":"特に、まろやかな味のカップ麺は常にストックを確保してくれ！\\n辛いものは食べられないんだよ！","ENG":"Always have it filled up with those mild-flavored cup ramen! I can’t eat spicy food!","TWN":"一定要常備不辣的泡麵！因為我不能吃辣的嘛～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"연습시간을 포함한, 하루 총 근무 시간은 16시간 이하! 그 이상은 절대 안돼!!","JPN":"訓練時間を含めて、1日の合計勤務時間は16時間以下！\\nそれ以上は絶対ダメ！！","ENG":"Work hours, including training, have to be under 16 hours! There’s no negotiating that!!","TWN":"包括練習時間在內，一天的工時不能超過16小時！我絕對不接受加班！！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"그리고 난 전투 요원으로 계약하는 거니까 무대 청소나 뒷정리 같은 건 저어어얼대 안 할 거라구?","JPN":"そして私は戦闘要員として契約するのだから、舞台の掃除や後片付けなどはぜーったいにやらないからね！","ENG":"Also, I’m going to work as a combatant, so cleaning is not in my job description, got that?","TWN":"還有，我的工作內容是負責戰鬥，什麼掃廁所，還是場地清潔的事，我可是絕～～～對不會做的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"으음……. 그리고…… 또……","JPN":"えーと……あとは……なんだっけ……","ENG":"Um... And... Also...","TWN":"嗯……還有……還有……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"……응? 계약서를 보라고?","JPN":"……うん？　契約書を見ろって？","ENG":"...Huh? You want me to read the contract?","TWN":"……嗯？叫我看一下合約嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"……우, 우와아앗!? 여, 여, 여기 적힌 게 정말이야?","JPN":"……え、えええっ！？ こ、こ、ここに書かれているのは本当？","ENG":"...W-what?! I-is what is written here is real?","TWN":"……哇哇哇！！這…這上面寫的都是真的嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"우으……","JPN":"うう……","ENG":"Err...","TWN":"哇賽……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"아냐, 아직 부족해, 아직 하나 남았다구!","JPN":"いや、まだ足りない。あと一つ追加で！","ENG":"No. It’s still not enough. I have one more!","TWN":"不！還不夠！還有一條！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_ALPHA_BUNNY_NULL","text":{"KOREA":"그럼…… 그럼! 마지막으로 나와 함께 평생 파사의 길을 걷겠다고 맹세해줘!","JPN":"じゃ……じゃあ！　最後に私と共に、一生破邪の道を歩むと誓ってよ！","ENG":"Then... Oh! I want you to promise me that you’ll devote yourself to the eradication of evil with me forever!","TWN":"就是……就是！你發誓！你會一直陪我一起走這條破邪之路！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_BUNNY_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};